INSERT INTO questions
  (id, specialty, stem, choices, correct_answer, explanation, telemetry, domain_name, subtopic, difficulty, "references", status, category)
VALUES
('authored-batch-r20-001', 'Trauma, Burns & Critical Events', 'A healthy, muscular 24-year-old man undergoes general anesthesia for arthroscopic shoulder surgery. During emergence and extubation he develops vigorous laryngospasm with marked sternal retractions and stridor before the airway is re-secured with positive-pressure mask ventilation and a small dose of succinylcholine. Within 10 minutes of relieving the obstruction he becomes progressively hypoxemic (SpO2 84% on 100% oxygen), develops pink frothy secretions in the airway, and bilateral diffuse crackles. He is afebrile and normotensive, and a portable chest radiograph shows bilateral perihilar alveolar infiltrates with a normal cardiac silhouette. Which mechanism best explains this patient''s acute hypoxemia?', '[{"text":"Markedly negative intrathoracic pressure from forced inspiration against a closed glottis increasing transcapillary fluid flux","label":"A","correct":true,"rationale":"Correct: vigorous inspiratory effort against the obstructed airway generates large negative intrathoracic pressure that raises venous return and transpulmonary capillary hydrostatic gradients, producing negative-pressure (post-obstructive) pulmonary edema."},{"text":"Aspiration of acidic gastric contents during the obstructive episode","label":"B","correct":false,"rationale":"Aspiration can cause hypoxemia and infiltrates, but it typically produces unilateral or gravity-dependent (often right lower lobe) opacities and lacks the characteristic temporal link to forceful inspiration against a closed glottis."},{"text":"Acute decompensated left ventricular systolic failure from anesthetic-induced cardiomyopathy","label":"C","correct":false,"rationale":"This young healthy patient has no cardiac history and a normal cardiac silhouette, and anesthetics do not acutely produce systolic heart failure of this kind."},{"text":"IgE-mediated anaphylaxis to neuromuscular blocking agents causing capillary leak","label":"D","correct":false,"rationale":"Anaphylaxis would be expected to cause hypotension, bronchospasm, and often cutaneous signs rather than isolated post-obstructive pulmonary edema in a hemodynamically stable patient."},{"text":"Methemoglobinemia from a topical local anesthetic applied to the airway","label":"E","correct":false,"rationale":"Methemoglobinemia causes a saturation gap and chocolate-brown blood with a normal chest film, not bilateral alveolar infiltrates and frothy pulmonary edema."}]'::jsonb, 'A', 'Negative-pressure (post-obstructive) pulmonary edema classically occurs in young, muscular patients who generate large negative intrathoracic pressures by inspiring forcefully against an obstructed airway, most often laryngospasm at extubation. The negative pressure increases venous return and right ventricular preload while raising the transpulmonary hydrostatic gradient, driving fluid into the alveoli; the result is rapid-onset hypoxemia with frothy secretions and bilateral perihilar infiltrates and a normal heart size. Management is supportive with supplemental oxygen, maintenance of a patent airway, and CPAP/PEEP or noninvasive ventilation; it is usually self-limited and resolves within 12 to 48 hours, and aggressive diuresis is rarely needed.', '{}'::jsonb, 'Subspecialty Care', 'Negative-pressure (post-obstructive) pulmonary edema after laryngospasm', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/postobstructive-pulmonary-edema/","source":"Postobstructive Pulmonary Edema - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Trauma, Burns & Critical Events'),
('authored-batch-r20-002', 'Trauma, Burns & Critical Events', 'A 38-year-old semiconductor-plant worker is brought to the OR for debridement after splashing concentrated hydrofluoric acid on both hands and forearms (~6% total body surface area). The skin was copiously irrigated at the scene. He reports severe, deep, throbbing pain out of proportion to the modest-appearing burns. On the monitor you note frequent premature ventricular contractions and a prolonging QT interval, and he complains of perioral and finger tingling. A point-of-care ionized calcium is low. In addition to topical and infiltrative calcium therapy at the burn site, which intervention most directly addresses the life-threatening derangement driving his arrhythmia?', '[{"text":"Administer intravenous sodium bicarbonate to alkalinize and neutralize residual acid","label":"A","correct":false,"rationale":"Systemic bicarbonate does not correct the fluoride-induced electrolyte depletion responsible for the arrhythmia and risks worsening ionized hypocalcemia by increasing calcium binding to albumin."},{"text":"Administer intravenous calcium (and replace magnesium) to correct fluoride-induced hypocalcemia and hypomagnesemia","label":"B","correct":true,"rationale":"Correct: absorbed fluoride avidly chelates calcium and magnesium, producing systemic hypocalcemia/hypomagnesemia with QT prolongation and ventricular dysrhythmias, so intravenous calcium and magnesium repletion is the priority systemic therapy."},{"text":"Give intravenous potassium chloride to treat presumed hypokalemia from acid exposure","label":"C","correct":false,"rationale":"Fluoride toxicity classically causes hyper-, not hypo-, kalemia from cellular efflux, so empiric potassium loading could precipitate dangerous hyperkalemia."},{"text":"Start an insulin-dextrose infusion to shift potassium intracellularly","label":"D","correct":false,"rationale":"Insulin-dextrose treats hyperkalemia but does nothing to replace the depleted calcium and magnesium that are the proximate cause of the QT prolongation and ectopy."},{"text":"Administer intralipid (20% lipid emulsion) as a sink for the absorbed fluoride","label":"E","correct":false,"rationale":"Lipid emulsion rescue is for lipophilic local anesthetic and similar drug toxicity; fluoride is a small water-soluble ion that lipid emulsion cannot sequester."}]'::jsonb, 'B', 'Hydrofluoric acid is a weak acid whose danger lies in the highly reactive fluoride ion, which penetrates tissue and avidly binds calcium and magnesium, producing severe systemic hypocalcemia and hypomagnesemia. The resulting QT prolongation, ventricular ectopy, and risk of fatal arrhythmia can occur even with small-surface-area burns, and pain is characteristically out of proportion to skin findings. Treatment is twofold: local calcium (topical gel, subcutaneous infiltration, or intra-arterial infusion) to bind fluoride in tissue, plus aggressive intravenous calcium and magnesium repletion with continuous ECG monitoring; fluoride can also cause hyperkalemia, which is treated concurrently.', '{}'::jsonb, 'Subspecialty Care', 'Hydrofluoric acid chemical burn with systemic hypocalcemia', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK441829/","source":"Hydrofluoric Acid Burns - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Trauma, Burns & Critical Events'),
('authored-batch-r20-003', 'Trauma, Burns & Critical Events', 'A 29-year-old man is brought to the trauma bay after an enclosed-space industrial explosion. He has no penetrating wounds but reports dyspnea and hemoptysis. Vitals: HR 118, BP 104/70, RR 32, SpO2 88% on a non-rebreather. Exam shows bilateral ruptured tympanic membranes and diffuse crackles; chest radiograph reveals a bilateral ''butterfly'' alveolar infiltrate pattern without rib fractures or pneumothorax. As you prepare him for emergent anesthesia, which statement most accurately guides safe management of his primary blast lung injury?', '[{"text":"Ruptured tympanic membranes reliably exclude significant blast lung injury, so aggressive positive-pressure ventilation is safe","label":"A","correct":false,"rationale":"Tympanic membrane rupture indicates exposure to substantial overpressure but does not exclude or predict the severity of pulmonary injury, and it should heighten, not lower, concern."},{"text":"Large-volume crystalloid resuscitation to a supranormal preload is the priority to optimize oxygen delivery","label":"B","correct":false,"rationale":"Over-resuscitation worsens blast lung edema and oxygenation, so judicious fluid management rather than aggressive volume loading is preferred when hemorrhage is not the dominant problem."},{"text":"Use lung-protective low-tidal-volume ventilation and maintain high vigilance for tension pneumothorax and systemic air embolism","label":"C","correct":true,"rationale":"Correct: primary blast lung injury is managed like ARDS with low-tidal-volume, pressure-limited ventilation, judicious fluids, and constant readiness for pneumothorax and arterial air embolism, which can be precipitated by positive-pressure ventilation."},{"text":"High tidal volumes and high airway pressures should be used to recruit the injured alveoli","label":"D","correct":false,"rationale":"High tidal volumes and pressures increase barotrauma and the risk of alveolar rupture and arterial air embolism in blast-injured lungs and are specifically harmful."},{"text":"Nitrous oxide is the preferred maintenance agent because it reduces opioid requirements","label":"E","correct":false,"rationale":"Nitrous oxide expands gas-filled spaces and is contraindicated given the high risk of occult pneumothorax and air embolism in blast lung."}]'::jsonb, 'C', 'Primary blast injury results from the overpressure wave acting on gas-containing organs; the lung is most vulnerable, producing alveolar hemorrhage and edema (a ''butterfly'' radiographic pattern) that behaves like ARDS. Positive-pressure ventilation is hazardous because alveolar disruption predisposes to tension pneumothorax and to systemic arterial air embolism, so clinicians should use low tidal volumes and limited airway pressures, avoid nitrous oxide, resuscitate fluids judiciously, and decompress the chest promptly if hemodynamics deteriorate. Tympanic membrane rupture signals significant blast exposure but neither confirms nor rules out the severity of pulmonary or other internal injury.', '{}'::jsonb, 'Subspecialty Care', 'Primary blast (blast lung) injury and ventilation strategy', 'hard', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK430914/","source":"Blast Injuries - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Trauma, Burns & Critical Events'),
('authored-batch-r20-004', 'Thoracic & Vascular', 'A 64-year-old man with COPD undergoes right upper lobectomy via video-assisted thoracoscopy under general anesthesia with a left-sided double-lumen tube. Twenty minutes after the surgeon collapses the right lung and one-lung ventilation begins, the SpO2 drifts from 98% to 84% on FiO2 1.0. Fiberoptic bronchoscopy confirms the tube is correctly positioned and the dependent (left) lung is well aspirated and inflating normally; tidal volume is 6 mL/kg, plateau pressure is 24 cmH2O, and the patient is hemodynamically stable. The surgeon can tolerate a brief pause but does not want the operative lung re-inflated. What is the most appropriate next intervention to improve oxygenation?', '[{"text":"Increase the dependent-lung tidal volume to 10 mL/kg to recruit more alveoli","label":"A","correct":false,"rationale":"Incorrect: large tidal volumes overdistend the dependent lung, raise its pulmonary vascular resistance, and divert blood to the nonventilated lung, worsening shunt and risking lung injury."},{"text":"Decrease FiO2 to 0.6 to limit absorption atelectasis in the dependent lung","label":"B","correct":false,"rationale":"Incorrect: with the patient already hypoxemic at 84%, lowering FiO2 removes the principal oxygen reserve and would deepen desaturation."},{"text":"Administer intravenous nitroglycerin to reduce pulmonary artery pressure","label":"C","correct":false,"rationale":"Incorrect: systemic vasodilators blunt hypoxic pulmonary vasoconstriction in the nonventilated lung, increasing shunt fraction and typically worsening oxygenation during one-lung ventilation."},{"text":"Apply 5-10 cmH2O CPAP with oxygen to the nondependent (operative) right lung","label":"D","correct":true,"rationale":"Correct: with tube position confirmed and the dependent lung optimized, low-level CPAP to the collapsed lung oxygenates blood traversing its persistent shunt and is the next maneuver that does not require full re-inflation."},{"text":"Permanently abandon one-lung ventilation and resume two-lung ventilation for the case","label":"E","correct":false,"rationale":"Incorrect: definitive two-lung ventilation is reserved for refractory or unstable hypoxemia, and the surgeon has explicitly asked to keep the operative lung collapsed, so less disruptive measures should be tried first."}]'::jsonb, 'D', 'Hypoxemia during one-lung ventilation is driven by transpulmonary shunt through the collapsed, nonventilated lung. After confirming correct tube position and optimizing the dependent lung (suctioning, appropriate tidal volume, and PEEP), the next step that improves oxygenation without re-inflating the surgical field is applying low-level CPAP with oxygen to the nondependent lung, which oxygenates the shunted blood. Maneuvers that raise dependent-lung pressures excessively or that blunt hypoxic pulmonary vasoconstriction (e.g., systemic vasodilators) tend to worsen the shunt. Reverting to two-lung ventilation is the rescue option for refractory or hemodynamically significant desaturation.', '{}'::jsonb, 'Subspecialty Care', 'One-lung ventilation: management of intraoperative hypoxemia', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/hypoxia-during-one-lung-ventilation/","source":"Hypoxia During One-Lung Ventilation - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Thoracic & Vascular'),
('authored-batch-r20-005', 'Thoracic & Vascular', 'A 72-year-old man undergoes open repair of an infrarenal abdominal aortic aneurysm. He has well-controlled hypertension and a remote coronary stent placed 4 years ago for stable angina; he is asymptomatic and on aspirin and a statin. An infrarenal aortic cross-clamp is applied. Compared with the hemodynamic response expected from a supraceliac clamp, which statement best describes the physiology of this infrarenal clamp and the patient''s preoperative ASA physical status?', '[{"text":"Preload reliably increases as blood shifts proximally, identical to a supraceliac clamp; the patient is ASA II","label":"A","correct":false,"rationale":"Incorrect: a reliable preload rise requires a supraceliac clamp, and a remote coronary stent classifies him as ASA III rather than ASA II."},{"text":"Preload typically does not rise because the splanchnic bed absorbs the volume; the patient is ASA II","label":"B","correct":false,"rationale":"Incorrect: the preload physiology is right, but a remote coronary stent (CAD) places him at ASA III, not ASA II."},{"text":"Preload reliably increases because all infrarenal clamps redirect splanchnic blood centrally; the patient is ASA III","label":"C","correct":false,"rationale":"Incorrect: the ASA class is correct, but infrarenal clamping characteristically does NOT raise preload because the splanchnic veins sequester the displaced volume."},{"text":"Preload falls sharply from acute afterload reduction; the patient is ASA IV","label":"D","correct":false,"rationale":"Incorrect: cross-clamping raises afterload rather than reducing it, and a remote stable coronary stent without decompensation does not meet ASA IV criteria for a constant threat to life."},{"text":"Preload typically does not rise because the splanchnic venous bed absorbs the displaced volume; the patient is ASA III","label":"E","correct":true,"rationale":"Correct: with the clamp below the splanchnic outflow, blood displaced from below the clamp is accommodated by the compliant splanchnic veins so central preload usually does not increase, and a remote coronary stent makes him ASA III even when asymptomatic."}]'::jsonb, 'E', 'The hemodynamic impact of aortic cross-clamping depends critically on clamp level relative to the splanchnic vasculature. A supraceliac clamp shifts blood from below the clamp into the central circulation and reliably increases preload, whereas an infraceliac/infrarenal clamp allows the compliant splanchnic venous bed to absorb the displaced volume, so preload generally does not rise. For ASA physical status, a remote (greater than 3 months) coronary stent or established CAD is ASA III even when the patient is asymptomatic and optimized; well-controlled hypertension alone would be only ASA II and should not be additively stacked into a higher class.', '{}'::jsonb, 'Subspecialty Care', 'Aortic cross-clamp hemodynamics and ASA physical status in AAA repair', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/aortic-cross-clamping/","source":"Aortic Cross-Clamping - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Thoracic & Vascular'),
('authored-batch-r20-006', 'Thoracic & Vascular', 'A 70-year-old woman undergoes carotid endarterectomy for symptomatic 80% internal carotid stenosis under superficial cervical plexus block with the patient awake for continuous neurologic assessment. Baseline blood pressure is 150/80 mmHg. Moments after the surgeon applies the carotid cross-clamp, the patient becomes confused, develops slurred speech, and cannot squeeze a ball with the contralateral hand; the surgeon has not yet placed a shunt. What is the most appropriate immediate management?', '[{"text":"Pharmacologically raise mean arterial pressure toward and above baseline while the surgeon places a carotid shunt","label":"A","correct":true,"rationale":"Correct: a new deficit on clamping signals inadequate collateral flow through the circle of Willis, and raising MAP augments contralateral perfusion while shunt placement restores antegrade flow."},{"text":"Administer labetalol to lower blood pressure and reduce cerebral metabolic demand","label":"B","correct":false,"rationale":"Incorrect: lowering blood pressure during clamp-induced ischemia further reduces collateral cerebral perfusion pressure and would worsen the deficit."},{"text":"Immediately convert to general anesthesia and intubate to secure the airway","label":"C","correct":false,"rationale":"Incorrect: emergent conversion abolishes the awake neurologic exam and delays the corrective steps of raising pressure and shunting, which directly address the ischemia."},{"text":"Give a 500 mL crystalloid bolus and continue observation without shunting","label":"D","correct":false,"rationale":"Incorrect: a fluid bolus alone neither rapidly augments cerebral perfusion pressure during clamping nor restores antegrade carotid flow, and passive observation risks infarction."},{"text":"Deepen the cervical plexus block with additional local anesthetic to control the patient","label":"E","correct":false,"rationale":"Incorrect: additional local anesthetic does nothing for cerebral ischemia and risks complications such as phrenic nerve block without addressing the deficit."}]'::jsonb, 'A', 'During awake carotid endarterectomy, a new neurologic deficit appearing at cross-clamp application indicates that collateral flow through the circle of Willis is insufficient to perfuse the ipsilateral hemisphere. The immediate response is to raise mean arterial pressure toward or above baseline to drive contralateral collateral flow and to place an intraluminal shunt to restore antegrade perfusion. Lowering blood pressure, deepening the block, or simply observing would deepen ischemia, and emergent conversion to general anesthesia sacrifices the real-time neurologic monitoring that makes the awake technique valuable.', '{}'::jsonb, 'Subspecialty Care', 'Carotid endarterectomy: awake regional anesthesia and cross-clamp neuromonitoring', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/carotid-stenosis/","source":"Carotid Stenosis - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Thoracic & Vascular');
